SELECT DISTINCT ?member (YEAR(?electionDate) AS ?electionYear) WHERE {
  wd:Q1015022 wdt:P31 wd:Q5223866 ;
                wdt:P131 wd:Q232 .
  ?district wdt:P131 wd:Q1015022 .
  ?member wdt:P2317 wd:Q124801 ;
          wdt:P1419 ?district ;
          wdt:P571 ?electionDate .
  ?member wdt:P106 ?occupation .
  ?occupation rdfs:label ?occLabel .
  FILTER (CONTAINS(UCASE(STR(?occLabel)), 'SLOT CAR') || CONTAINS(UCASE(STR(?occLabel)), 'RACING'))
  FILTER (LANG(?occLabel) = 'en')
}

